1	#pragma once
2	
3	#include <algorithm>
4	#include "physical_types.h"
5	
6	#include "vtr_assert.h"
7	#include "vtr_flat_map.h"
8	#include "vpr_types.h"
9	
10	struct t_compressed_block_grid {
11	    // The compressed grid of a block type stores only the coordinates that are occupied by that particular block type.
12	    // For instance, if a DSP block exists only in the 2nd, 3rd, and 5th columns, the compressed grid of X axis will solely store the values 2, 3, and 5.
13	    // Consequently, the compressed to_grid_x will contain only three members. The same approach is applicable to other compressed directions.
14	    // This compressed data structure helps to move blocks in a more efficient way. For instance, if I need to move a DSP block to the next compatible column, I can simply get
15	    // the next compatible column number by accessing the next element in the compressed grid instead of iterating over all columns to find the next compatible column.
16	    //If 'cx' is an index in the compressed grid space, then
17	    //'compressed_to_grid_x[cx]' is the corresponding location in the
18	    //full (uncompressed) device grid.
19	    std::vector<std::vector<int>> compressed_to_grid_x; // [0...num_layers-1][0...num_columns-1] -> uncompressed x
20	    std::vector<std::vector<int>> compressed_to_grid_y; // [0...num_layers-1][0...num_rows-1] -> uncompressed y
21	    std::vector<int> compressed_to_grid_layer;          // [0...num_layers-1] -> uncompressed layer
22	
23	    //The grid is stored with a full/dense x-dimension (since only
24	    //x values which exist are considered), while the y-dimension is
25	    //stored sparsely, since we may not have full columns of blocks.
26	    //This makes it easy to check whether there exist
27	    std::vector<std::vector<vtr::flat_map2<int, t_physical_tile_loc>>> grid;
28	
29	    //The sub type compatibility for a given physical tile and a compressed block grid
30	    //corresponding to the possible placement location for a given logical block
31	    //  - key: physical tile index
32	    //  - value: vector of compatible sub tiles for the physical tile/logical block pair
33	    std::unordered_map<int, std::vector<int>> compatible_sub_tiles_for_tile;
34	
35	    inline size_t get_num_columns(int layer_num) const {
36	        return compressed_to_grid_x[layer_num].size();
37	    }
38	
39	    inline size_t get_num_rows(int layer_num) const {
40	        return compressed_to_grid_y[layer_num].size();
41	    }
42	
43	    inline t_physical_tile_loc grid_loc_to_compressed_loc(t_physical_tile_loc grid_loc) const {
44	        int cx = UNDEFINED;
45	        int cy = UNDEFINED;
46	        int layer_num = grid_loc.layer_num;
47	
48	        auto itr_x = std::ranges::lower_bound(compressed_to_grid_x[layer_num], grid_loc.x);
49	        VTR_ASSERT(*itr_x == grid_loc.x);
50	        cx = std::distance(compressed_to_grid_x[layer_num].begin(), itr_x);
51	
52	        auto itr_y = std::ranges::lower_bound(compressed_to_grid_y[layer_num], grid_loc.y);
53	        VTR_ASSERT(*itr_y == grid_loc.y);
54	        cy = std::distance(compressed_to_grid_y[layer_num].begin(), itr_y);
55	
56	        return {cx, cy, layer_num};
57	    }
58	
59	    /**
60	     * @brief Converts a grid location to its corresponding compressed location, rounding up where necessary.
61	     *
62	     * This function takes a physical tile location in the grid and converts it to the corresponding
63	     * compressed location. The conversion approximates by rounding up to the nearest valid compressed location.
64	     * If all the compressed locations are less than the grid location, the function will return the last compressed location.
65	     *
66	     * @param grid_loc The physical tile location in the grid.
67	     * @return The corresponding compressed location with the same layer number.
68	     */
69	    inline t_physical_tile_loc grid_loc_to_compressed_loc_approx_round_up(t_physical_tile_loc grid_loc) const {
70	        auto find_compressed_index = [](const std::vector<int>& compressed, int value) -> int {
71	            // Get the first element that is not less than the value
72	            auto itr = std::ranges::lower_bound(compressed, value);
73	            if (itr == compressed.end()) {
74	                // If all the compressed locations are less than the grid location, return the last compressed location
75	                return compressed.size() - 1;
76	            } else {
77	                // Return the index of the first element that is not less than the value
78	                return std::distance(compressed.begin(), itr);
79	            }
80	        };
81	
82	        int layer_num = grid_loc.layer_num;
83	        int cx = find_compressed_index(compressed_to_grid_x[layer_num], grid_loc.x);
84	        int cy = find_compressed_index(compressed_to_grid_y[layer_num], grid_loc.y);
85	
86	        return {cx, cy, layer_num};
87	    }
88	
89	    /**
90	     * @brief Converts a grid location to its corresponding compressed location, rounding down where necessary.
91	     *
92	     * This function takes a physical tile location in the grid and converts it to the corresponding
93	     * compressed location. The conversion approximates by rounding down to the nearest valid compressed location.
94	     * If all the compressed locations are bigger than the grid location, the function will return the first compressed location.
95	     *
96	     * @param grid_loc The physical tile location in the grid.
97	     * @return The corresponding compressed location with the same layer number.
98	     */
99	    inline t_physical_tile_loc grid_loc_to_compressed_loc_approx_round_down(t_physical_tile_loc grid_loc) const {
100	        auto find_compressed_index = [](const std::vector<int>& compressed, int value) -> int {
101	            // Get the first element that is strictly bigger than the value
102	            auto itr = std::ranges::upper_bound(compressed, value);
103	            if (itr == compressed.begin()) {
104	                // If all the compressed locations are bigger than the grid location, return the first compressed location
105	                return 0;
106	            } else {
107	                // Return the index of the first element that is less than or equal to the value
108	                return std::distance(compressed.begin(), itr - 1);
109	            }
110	        };
111	
112	        int layer_num = grid_loc.layer_num;
113	        int cx = find_compressed_index(compressed_to_grid_x[layer_num], grid_loc.x);
114	        int cy = find_compressed_index(compressed_to_grid_y[layer_num], grid_loc.y);
115	
116	        return {cx, cy, layer_num};
117	    }
118	
119	    /**
120	     * @brief  find the nearest location in the compressed grid.
121	     *
122	     * Useful when the point is of a different block type from coords.
123	     *
124	     *   @param grid_loc non-compressed physical tile location in the grid
125	     *   @return Nearest x and y compressed locations in the grid (in the same layer),
126	     *           or OPEN if a location does not exist.
127	     */
128	    inline t_physical_tile_loc grid_loc_to_compressed_loc_approx(t_physical_tile_loc grid_loc) const {
129	        auto find_closest_compressed_point = [](int loc, const std::vector<int>& compressed_grid_dim) -> int {
130	            // If the compressed grid dim's size is 0, this means that there are
131	            // no compatible locations for a block of the given type. Returns OPEN
132	            // in that case.
133	            if (compressed_grid_dim.size() == 0) {
134	                return UNDEFINED;
135	            }
136	
137	            // Find the first element not less than loc
138	            auto itr = std::ranges::lower_bound(compressed_grid_dim, loc);
139	
140	            if (itr == compressed_grid_dim.begin()) {
141	                // If all the compressed locations are bigger that or equal to loc, return the first compressed location
142	                return 0;
143	            } else if (itr == compressed_grid_dim.end()) {
144	                // If all the compressed locations are less than loc, return the last compressed location
145	                return compressed_grid_dim.size() - 1;
146	            } else {
147	                // Find the nearest compressed location.
148	                int dist_prev = loc - *(itr - 1);
149	                int dist_next = *itr - loc;
150	                VTR_ASSERT_DEBUG(dist_prev >= 0 && dist_next >= 0);
151	                return (dist_prev <= dist_next) ? (std::distance(compressed_grid_dim.begin(), itr - 1)) : (std::distance(compressed_grid_dim.begin(), itr));
152	            }
153	        };
154	
155	        const int layer_num = grid_loc.layer_num;
156	        const int cx = find_closest_compressed_point(grid_loc.x, compressed_to_grid_x[layer_num]);
157	        const int cy = find_closest_compressed_point(grid_loc.y, compressed_to_grid_y[layer_num]);
158	
159	        return {cx, cy, layer_num};
160	    }
161	
162	    inline t_physical_tile_loc compressed_loc_to_grid_loc(t_physical_tile_loc compressed_loc) const {
163	        int layer_num = compressed_loc.layer_num;
164	        return {compressed_to_grid_x[layer_num][compressed_loc.x], compressed_to_grid_y[layer_num][compressed_loc.y], layer_num};
165	    }
166	
167	    inline const std::vector<int>& compatible_sub_tile_num(int physical_type_index) const {
168	        return compatible_sub_tiles_for_tile.at(physical_type_index);
169	    }
170	
171	    inline const vtr::flat_map2<int, t_physical_tile_loc>& get_column_block_map(int cx, int layer_num) const {
172	        VTR_ASSERT_SAFE(layer_num < (int)grid.size());
173	        VTR_ASSERT_SAFE(cx < (int)grid[layer_num].size());
174	        return grid[layer_num][cx];
175	    }
176	
177	    inline const std::vector<int>& get_layer_nums() const {
178	        return compressed_to_grid_layer;
179	    }
180	};
181	
182	//Compressed grid space for each block type
183	//Used to efficiently find logically 'adjacent' blocks of the same block type even though
184	//the may be physically far apart
185	typedef std::vector<t_compressed_block_grid> t_compressed_block_grids;
186	
187	std::vector<t_compressed_block_grid> create_compressed_block_grids();
188	
189	/**
190	 * @brief  print the contents of the compressed grids to an echo file
191	 *
192	 *   @param filename the name of the file to print to
193	 *   @param comp_grids the compressed grids that are used during placement
194	 *
195	 */
196	void echo_compressed_grids(const char* filename, const std::vector<t_compressed_block_grid>& comp_grids);
197

